INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('gav_readout_panel_ignores_per_state_extras_config', 'galvanometer_to_ammeter_voltmeter: the #sliders readout renders all four derived values on every show_sliders state, leaking Voltmeter into the shunt-only S4 and Ammeter into the voltmeter-only S6 (contradicts the Rule-31c per-state control contract)', 'MODERATE', 'peter_parker:renderer_primitives', 'FIXED 2026-07-05 (field_3d_renderer.ts refreshGalvanometerExplorer). Was: the gav_readout innerHTML unconditionally listed Shunt S, Series R, Ammeter≈ and Voltmeter≈ whenever the panel was visible — so S4 (contextual controls Ig,G,I) still showed "Voltmeter ≈ 10000 Ω" and S6 (Ig,G,V) still showed "Ammeter ≈ 0.100 Ω", undoing the per-state contextual filtering the slider rows already did. Fix: the readout is now built from the current state''s visible_controls — has "I" ⇒ show the shunt-S/ammeter line, has "V" ⇒ show the series-R/voltmeter line, both (S9 sandbox) ⇒ both, absent ⇒ both (safe default). Same visible_controls gate as the slider rows.', 'A scenario readout/derived-value panel must be gated by the SAME per-state signal (visible_controls / extras.readout.fields) as its slider rows — never rendered unconditionally in the panel-init. A contextual-control state that hides a slider must also hide the readout line that slider drives, or the disclosure leaks.', 'manual', 'On S4 the readout shows only the shunt-S/ammeter line (no Voltmeter/Series-R); on S6 only the series-R/voltmeter line (no Ammeter/Shunt-S); on S9 both. Any state whose readout names the other meter is a leak.', 'FIXED', ARRAY['galvanometer_to_ammeter_voltmeter'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-05_gav_rule31_rebuild', 'incident'),
('gav_assemble_reveal_pin_missing_from_derive_state_meta', 'galvanometer_to_ammeter_voltmeter frozen capture photographs the PRE-assembly picture on S5/S7 — deriveStateMeta.maxRevealForField3dState has no gav block, so the assemble_ammeter/assemble_voltmeter one-shot reveals fall back to DEFAULT_REVEAL_MS (1500ms), far before the 8000–9000ms merge fires', 'MAJOR', 'peter_parker:renderer_primitives', 'FIXED 2026-07-05 (deriveStateMeta.ts). Was: no galvanometer_to_ammeter_voltmeter case in maxRevealForField3dState, so every state clamped to DEFAULT_REVEAL_MS (1500ms). STATE_5''s assemble_ammeter fires at 9000ms (+1500ms) and STATE_7''s assemble_voltmeter at 8000ms (+1500ms), so the frozen/H2-pin capture photographed the state BEFORE the G‖shunt→"A" and G+R→"V" merges completed, and no deterministic check caught it (some content is on screen so D1p/D5 pass trivially). Fix: added a gav block that pushes each assemble''s at_ms+duration_ms(+400) as a reveal candidate, pinning the frozen frame past the completed meter box.', 'Every new field_3d scenario_type whose per-state extras carry one-shot timed reveals (at_ms + duration_ms) MUST add a matching candidate block in deriveStateMeta.maxRevealForField3dState (mirroring every sibling scenario) — else the frozen capture pins at the 1500ms default and photographs the state before its payoff, invisibly to the deterministic gate. Add the scenario to deriveStateMeta at author time, alongside the renderer.', 'manual', 'grep deriveStateMeta.ts for the scenario_type / its reveal-extras keys (here assemble_ammeter/assemble_voltmeter). If absent while the concept has timed reveals, its frozen frames are mistimed. Verify the S5/S7 frozen frames show the assembled A/V meter box, not the pre-merge lens+resistor.', 'FIXED', ARRAY['galvanometer_to_ammeter_voltmeter'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-07-05_gav_rule31_rebuild', 'incident'),
('galvanometer_family_motion_expectation_undeclared', 'Neither moving_coil_galvanometer nor galvanometer_to_ammeter_voltmeter is declared in deriveMotionExpectations, so THE EYE D5/D6 dense-motion checks silently SKIP every state of both — the automated motion gate is hollow (never fails, never checks)', 'MODERATE', 'peter_parker:visual_validator', 'DEFERRED (tracked) 2026-07-05. deriveMotionExpectations has per-scenario motion blocks (gauss/acl/potential/capacitor/pef/em/mag/faraday/motional_emf/eddy) but NONE for the two galvanometer scenarios, and the field_3d loop never sees an advance_mode (that lives on epic_l_path, not field_3d_config), so both concepts'' states resolve to undefined → D5/D6 skip. The motion IS real (mcg coil deflection + current dots; gav continuous current-dot stream ∝ I + the S5/S7 assemble cross-fades) and eye-walker pixel-verified it on-frame (mcg run 20260705-045637, gav run 20260705-180427), so both sims are correct — only the automated gate is absent. NOT fixed drive-by: declaring motion on the slow-creep states (gav S1 = Ig-only trickle, gav S3/S4 shunt split) risks D6 false-fails near DENSE_MOTION_EPSILON, so it needs per-state tuning + a full EYE re-run to confirm. Fix in a dedicated validator pass covering both galvanometers together.', 'A new field_3d scenario with continuous or one-shot motion should be declared in deriveMotionExpectations (true for guided motion states, false/undefined for show_sliders/interactive) so D5/D6 actually gate it — an undeclared scenario passes THE EYE trivially without ever checking motion. Pair the declaration with a full EYE re-run to confirm the dense motion clears the floor on the slowest state.', 'manual', 'grep deriveMotionExpectations for the scenario_type / its per-state motion keys. If absent, D5/D6 skip and a "clean" EYE pass does not imply motion was verified — an eye-walker frame read is then load-bearing, not optional.', 'DEFERRED', ARRAY['galvanometer_to_ammeter_voltmeter', 'moving_coil_galvanometer'], ARRAY[]::text[], 'session_2026-07-05_gav_rule31_rebuild', 'incident')
